#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";

export const CODEX_SKILL_BUNDLE_ROOT = "plugins/bifrost-agent/codex-skills";

const PACKAGE_ROOT = "plugins/bifrost-agent";
const SOURCE_SKILLS_ROOT = `${PACKAGE_ROOT}/skills`;
const SOURCE_AGENTS_ROOT = `${PACKAGE_ROOT}/agents`;
const GENERATED_MARKER = "<!-- Generated by scripts/generate-codex-skill-bundle.mjs; do not edit directly. -->";

const AGENT_DISPLAY_NAMES = new Map([
  ["architect-reviewer", "brokk:architect-reviewer"],
  ["devops-reviewer", "brokk:devops-reviewer"],
  ["dry-reviewer", "brokk:dry-reviewer"],
  ["issue-diagnostician", "brokk:issue-diagnostician"],
  ["issue-enhancer", "brokk:issue-enhancer"],
  ["issue-planner", "brokk:issue-planner"],
  ["security-reviewer", "brokk:security-reviewer"],
  ["senior-dev-reviewer", "brokk:senior-dev-reviewer"],
]);

const REVIEW_AGENT_ORDER = [
  "security-reviewer",
  "dry-reviewer",
  "senior-dev-reviewer",
  "devops-reviewer",
  "architect-reviewer",
];

export function buildCodexSkillBundleFiles(repoRoot = process.cwd()) {
  const skillsRoot = path.join(repoRoot, SOURCE_SKILLS_ROOT);
  const skillDirs = fs.readdirSync(skillsRoot, { withFileTypes: true })
    .filter((entry) => entry.isDirectory())
    .map((entry) => entry.name)
    .sort();

  return skillDirs.map((skillDir) => {
    const sourcePath = path.join(skillsRoot, skillDir, "SKILL.md");
    const source = fs.readFileSync(sourcePath, "utf8");
    const content = codexizeSkill(source, repoRoot);
    return [path.join(skillDir, "SKILL.md"), content];
  });
}

function codexizeSkill(source, repoRoot) {
  const referencedAgents = referencedAgentNames(source);
  let content = source;

  if (referencedAgents.length > 0) {
    content = rewriteAgentInstructions(content);
    content = `${content.trimEnd()}\n\n${buildAppendix(referencedAgents, repoRoot)}\n`;
  }

  return insertGeneratedMarker(content);
}

function insertGeneratedMarker(content) {
  if (!content.startsWith("---\n")) {
    return `${GENERATED_MARKER}\n\n${content}`;
  }

  const end = content.indexOf("\n---\n", "---\n".length);
  if (end === -1) {
    return `${GENERATED_MARKER}\n\n${content}`;
  }

  const frontmatterEnd = end + "\n---\n".length;
  return `${content.slice(0, frontmatterEnd)}\n${GENERATED_MARKER}\n\n${content.slice(frontmatterEnd)}`;
}

function referencedAgentNames(source) {
  const names = new Set();
  for (const match of source.matchAll(/`brokk:([a-z-]+)`/g)) {
    names.add(match[1]);
  }
  for (const match of source.matchAll(/`brokk:([a-z-]+)`\s+agent/g)) {
    names.add(match[1]);
  }

  const ordered = [
    "issue-diagnostician",
    "issue-planner",
    "issue-enhancer",
    ...REVIEW_AGENT_ORDER,
  ];
  return ordered.filter((name) => names.has(name));
}

function rewriteAgentInstructions(content) {
  return content
    .replaceAll("If the `Agent` tool is available", "If Codex subagent tools are available")
    .replaceAll("If the `Agent` tool is NOT available", "If Codex subagent tools are NOT available")
    .replaceAll("using parallel `Agent` tool calls", "using parallel Codex subagent tool calls")
    .replace(
      /Use the agent names\s+listed below as the `subagent_type`\./g,
      "Do not use the reviewer names below as Codex `agent_type` values. Codex does not load plugin-defined `brokk:*` subagent types; spawn generic Codex subagents and include the matching prompt from the Codex Specialist Prompt Appendix in each task.",
    )
    .replace(
      /Use the agent\s+names listed below as `subagent_type`\./g,
      "Do not use the reviewer names below as Codex `agent_type` values. Codex does not load plugin-defined `brokk:*` subagent types; spawn generic Codex subagents and include the matching prompt from the Codex Specialist Prompt Appendix in each task.",
    )
    .replace(
      /spawn an? `brokk:([a-z-]+)`\s+agent/g,
      (_match, agentName) => `spawn a generic Codex subagent using the \`${AGENT_DISPLAY_NAMES.get(agentName) ?? `brokk:${agentName}`}\` prompt from the Codex Specialist Prompt Appendix`,
    )
    .replace(
      /spawn a `brokk:([a-z-]+)`/g,
      (_match, agentName) => `spawn a generic Codex subagent using the \`${AGENT_DISPLAY_NAMES.get(agentName) ?? `brokk:${agentName}`}\` prompt from the Codex Specialist Prompt Appendix`,
    );
}

function buildAppendix(agentNames, repoRoot) {
  const sections = agentNames.map((agentName) => {
    const displayName = AGENT_DISPLAY_NAMES.get(agentName) ?? `brokk:${agentName}`;
    const agentPath = path.join(repoRoot, SOURCE_AGENTS_ROOT, `${agentName}.md`);
    const prompt = fs.readFileSync(agentPath, "utf8").trimEnd();
    return `### ${displayName}\n\n_Source: \`${SOURCE_AGENTS_ROOT}/${agentName}.md\`._\n\n\`\`\`markdown\n${prompt}\n\`\`\``;
  });

  return [
    "## Codex Specialist Prompt Appendix",
    "",
    "Codex plugin installs do not register plugin-defined `brokk:*` agent names as callable subagent types. When this workflow asks for a specialist agent, spawn a generic Codex subagent such as `default`, `explorer`, or `worker` as appropriate for the task, and include the matching prompt below verbatim in that subagent task. If Codex subagent tools are unavailable or the user has not authorized subagent work, perform the same analysis yourself using the corresponding prompt.",
    "",
    ...sections,
  ].join("\n");
}

function writeBundle(repoRoot = process.cwd()) {
  const outputRoot = path.join(repoRoot, CODEX_SKILL_BUNDLE_ROOT);
  if (fs.existsSync(outputRoot)) {
    assertGeneratedDirectory(outputRoot);
    fs.rmSync(outputRoot, { recursive: true, force: true });
  }

  for (const [relativePath, content] of buildCodexSkillBundleFiles(repoRoot)) {
    const outputPath = path.join(outputRoot, relativePath);
    fs.mkdirSync(path.dirname(outputPath), { recursive: true });
    fs.writeFileSync(outputPath, content);
  }
}

function assertGeneratedDirectory(outputRoot) {
  const stack = [outputRoot];
  while (stack.length > 0) {
    const current = stack.pop();
    for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
      const entryPath = path.join(current, entry.name);
      if (entry.isDirectory()) {
        stack.push(entryPath);
        continue;
      }
      if (!entry.isFile() || entry.name !== "SKILL.md") {
        continue;
      }
      const content = fs.readFileSync(entryPath, "utf8");
      if (!content.includes(GENERATED_MARKER)) {
        throw new Error(`${entryPath} is not marked as generated; refusing to overwrite it`);
      }
    }
  }
}

if (import.meta.url === `file://${process.argv[1]}`) {
  writeBundle();
}
